import math

def minFallingPathSum(matrix):
    m = len(matrix)
    n = len(matrix[0])

    if m == 0:
        return 0
    if n == 0:
        return 0
    if m == 1:
        return min(matrix[0])

    for r in range(1, m):
        for c in range(n):
            # Calculate the minimum sum from the previous row
            # that can fall to the current cell (r, c)

            # Option 1: Fall straight down from (r-1, c)
            prev_sum_straight = matrix[r-1][c]

            # Option 2: Fall diagonally left from (r-1, c-1)
            prev_sum_diag_left = math.inf
            if c > 0:
                prev_sum_diag_left = matrix[r-1][c-1]

            # Option 3: Fall diagonally right from (r-1, c+1)
            prev_sum_diag_right = math.inf
            if c < n - 1:
                prev_sum_diag_right = matrix[r-1][c+1]

            # Update the current cell's value with the minimum path sum to it
            matrix[r][c] += min(prev_sum_straight, prev_sum_diag_left, prev_sum_diag_right)

    # The minimum falling path sum will be the minimum value in the last row
    return min(matrix[m-1])
